import React, { useEffect } from 'react';

interface ToastProps { message:string; type:'success'|'error'|'info'|'warning'; onClose:()=>void; }

export default function Toast({ message, type, onClose }: ToastProps) {
  useEffect(() => { const t = setTimeout(onClose, 4000); return () => clearTimeout(t); }, [onClose]);
  const colors:any = { success:{bg:'#059669',border:'rgba(16,185,129,0.3)',icon:'✓'}, error:{bg:'#dc2626',border:'rgba(239,68,68,0.3)',icon:'✕'}, warning:{bg:'#d97706',border:'rgba(245,158,11,0.3)',icon:'⚠'}, info:{bg:'#3b82f6',border:'rgba(59,130,246,0.3)',icon:'ℹ'} };
  const c = colors[type];
  return (
    <div style={{ position:'fixed', bottom:28, right:28, zIndex:9999, display:'flex', alignItems:'center', gap:12, background:'#1e1e35', border:`1px solid ${c.border}`, color:'#f0eee8', padding:'14px 18px', borderRadius:14, boxShadow:'0 8px 32px rgba(0,0,0,0.5)', animation:'slideIn .3s cubic-bezier(.16,1,.3,1)', minWidth:280, maxWidth:380 }}>
      <style>{`@keyframes slideIn{from{opacity:0;transform:translateX(40px)}to{opacity:1;transform:translateX(0)}}`}</style>
      <div style={{ width:32, height:32, borderRadius:9, background:c.bg, display:'flex', alignItems:'center', justifyContent:'center', fontSize:14, fontWeight:700, flexShrink:0 }}>{c.icon}</div>
      <div style={{ flex:1, fontSize:14, lineHeight:1.4 }}>{message}</div>
      <button onClick={onClose} style={{ background:'rgba(255,255,255,0.08)', border:'none', color:'rgba(255,255,255,0.5)', width:24, height:24, borderRadius:6, cursor:'pointer', fontSize:12, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center' }}>✕</button>
    </div>
  );
}
